diff --git a/pkg/skiplist/skiplist_lowerbound_test.go b/pkg/skiplist/skiplist_lowerbound_test.go
new file mode 100644
--- /dev/null
+++ b/pkg/skiplist/skiplist_lowerbound_test.go
@@
+package skiplist
+
+import "testing"
+
+// TestRange_IncludesLowerBound verifies that Range includes the entry whose
+// key equals the lower bound. On the broken base this returns 2 (drops "a").
+func TestRange_IncludesLowerBound(t *testing.T) {
+	sl := New(42)
+	for _, k := range []string{"a", "b", "c"} {
+		sl.Insert(k, 1)
+	}
+	got := sl.Range("a", "c")
+	if len(got) != 3 {
+		t.Fatalf("expected 3 entries including lower bound, got %d", len(got))
+	}
+}

